import android.content.Context
import android.content.SharedPreferences

class AuthManager(private val context: Context) {

    private val sharedPreferences: SharedPreferences by lazy {
        context.getSharedPreferences(PREFS_FILE_NAME, Context.MODE_PRIVATE)
    }

    companion object {
        private const val PREFS_FILE_NAME = "auth_prefs"
        private const val KEY_USER_ID = "user_id"
        private const val KEY_AUTH_TOKEN = "auth_token"
    }

    /**
     * Represents the data for an authenticated user session.
     */
    data class AuthSession(
        val userId: String,
        val authToken: String
    )

    /**
     * Saves the user ID and authentication token to SharedPreferences.
     * Call this after a successful login or token refresh.
     *
     * @param userId The unique identifier for the user.
     * @param authToken The authentication token received from the server.
     */
    fun saveAuthData(userId: String, authToken: String) {
        sharedPreferences.edit().apply {
            putString(KEY_USER_ID, userId)
            putString(KEY_AUTH_TOKEN, authToken)
            apply() // Use apply for asynchronous write to SharedPreferences
        }
    }

    /**
     * Retrieves the stored authentication data.
     *
     * @return An [AuthSession] object if data exists, otherwise null.
     */
    fun getAuthData(): AuthSession? {
        val userId = sharedPreferences.getString(KEY_USER_ID, null)
        val authToken = sharedPreferences.getString(KEY_AUTH_TOKEN, null)

        return if (userId != null && authToken != null) {
            AuthSession(userId, authToken)
        } else {
            null
        }
    }

    /**
     * Clears all stored authentication data, effectively logging the user out.
     */
    fun clearAuthData() {
        sharedPreferences.edit().apply {
            remove(KEY_USER_ID)
            remove(KEY_AUTH_TOKEN)
            apply()
        }
    }

    /**
     * Checks if a user is currently logged in (i.e., auth data is present).
     *
     * @return True if auth data exists, false otherwise.
     */
    fun isLoggedIn(): Boolean {
        return getAuthData() != null
    }
}